SELECT (YEAR(?date) AS ?year) WHERE {
  ?event rdfs:label ?eventLabel ;
         wdt:P136 wd:Q11229 ;
         wdt:P1257 ?olympics .
  FILTER (CONTAINS(LCASE(?eventLabel), "women") && LANG(?eventLabel) = "en") .
  ?olympics wdt:P585 ?date .
} ORDER BY DESC(?date) LIMIT 1

SELECT (YEAR(?date) AS ?year) WHERE {
  ?event wdt:P136 wd:Q11229;
         rdfs:label ?label;
         wdt:P1257 ?olympics.
  FILTER (CONTAINS(LCASE(?label), "women's ice hockey") && LANG(?label) = "en").
  ?olympics wdt:P31 wd:Q12019;
          wdt:P585 ?date.
} ORDER BY DESC(?date) LIMIT 1

